SELECT u.*, ste.site_nm AS site_nm, cpn.coupon_nm AS coupon_id_nm, mem.member_nm AS member_nm, ord.member_nm AS order_nm, ite.prod_nm AS order_item_nm, prd.prod_nm AS prod_nm FROM pm_coupon_usage u LEFT JOIN sy_site ste ON ste.site_id = u.site_id LEFT JOIN pm_coupon cpn ON cpn.coupon_id = u.coupon_id LEFT JOIN mb_member mem ON mem.member_id = u.member_id LEFT JOIN od_order ord ON ord.order_id = u.order_id LEFT JOIN od_order_item ite ON ite.order_item_id = u.order_item_id LEFT JOIN pd_prod prd ON prd.prod_id = u.prod_id
ORDER BY u.usage_id ASC ORDER BY u.usage_id DESC ORDER BY u.coupon_nm ASC ORDER BY u.coupon_nm DESC ORDER BY u.reg_date ASC ORDER BY u.reg_date DESC ORDER BY u.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

